#include<bits/stdc++.h>
using namespace std;
#define next next0

const int N = 1e6 + 7;

string s, t;
int next[N], stk[N], f[N];

int main()
{
    int top = 0;
    cin >> t;
    cin >> s;
    s = '&' + s;
    t = "#" + t;
    int n = t.size() - 1;
    int m = s.size() - 1;
    int j = -1;
    for(int i = 2; i <= m; i++)
    {
        while(j && s[j + 1] != s[i]) j = next[j];
        if(s[j + 1] == s[i]) ++j;
        next[i] = j;
    }
    j = 0;
    for(int i = 1; i <= n; i++)
    {
        while(j && s[j + 1] != t[i]) j = next[j];
        if(s[j + 1] == t[i]) ++j;
        f[i] = j;
        stk[++top] = i;
        if(j == m) top -= m, j = f[stk[top]];
    }
    for(int i = 1; i <= top; i++)
        cout << t[stk[i]];
}
